import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import './ProblemSolverPage.css';

function ProblemSolverPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [problem, setProblem] = useState(null);
  const [code, setCode] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadProblem();
  }, [id]);

  const loadProblem = async () => {
    try {
      const [problemData, template] = await Promise.all([
        api.getProblem(id),
        api.getTemplate(id)
      ]);
      setProblem(problemData);
      setCode(template.template_code || '');
    } catch (error) {
      console.error('Failed to load problem:', error);
    }
  };

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const res = await api.submitCode({ problem: id, code });
      setResult(res);
      alert(res.status === 'Accepted' ? '✅ Accepted!' : `❌ ${res.status}`);
    } catch (error) {
      alert('Submission failed');
    } finally {
      setLoading(false);
    }
  };

  if (!problem) return <div className="loading">Loading...</div>;

  return (
    <div className="solver-page">
      <nav className="navbar">
        <button onClick={() => navigate('/problems')} className="btn-back">
          ← Back
        </button>
        <div className="nav-brand">{problem.title}</div>
      </nav>

      <div className="solver-layout">
        <div className="problem-panel">
          <h2>{problem.title}</h2>
          <span className={`badge ${problem.difficulty}`}>{problem.difficulty}</span>
          <div className="description">{problem.description}</div>
          <div className="example">
            <h3>Example</h3>
            <div><strong>Input:</strong> {problem.input_example}</div>
            <div><strong>Output:</strong> {problem.output_example}</div>
          </div>
        </div>

        <div className="editor-panel">
          <textarea
            value={code}
            onChange={(e) => setCode(e.target.value)}
            className="code-editor"
            spellCheck="false"
          />
          <button 
            onClick={handleSubmit} 
            disabled={loading}
            className="btn-submit"
          >
            {loading ? 'Submitting...' : '▶ Run Code'}
          </button>

          {result && (
            <div className={`result ${result.status === 'Accepted' ? 'success' : 'error'}`}>
              <div><strong>Status:</strong> {result.status}</div>
              <div><strong>Time:</strong> {result.execution_time}ms</div>
              {result.error_output && (
                <div><strong>Output:</strong> {result.error_output}</div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default ProblemSolverPage;
